```class Solution {
public:
    int magicalString(int n) {
        vector<int> magical(n);
        magical[0] = 1;
        int head = 0, tail = 2;
        for (int i = 1; i < n; i++) {
            if (magical[head] == 1) {
                magical[i] = 3 - magical[i - 1];
            } else {
                magical[i] = magical[i - 1];
            }
            if (--magical[head] == 0) {
                head++;
            }
            if (tail < n && magical[tail] > 0) {
                magical[++head] = magical[tail];
                tail++;
            }
        }
        int count = 0;
        for (int num : magical) {
            if (num == 1) count++;
        }
        return count;
    }
};
